Here are comprehensive unit tests for the `zip_dicts` function using pytest. The tests cover happy paths, edge cases, and error cases:

```python
import pytest

def test_zip_dicts_happy_path():
    """Test basic functionality with multiple dictionaries."""
    dict1 = {'a': 1, 'b': 2}
    dict2 = {'b': 3, 'c': 4}
    dict3 = {'a': 5, 'd': 6}

    result = zip_dicts(dict1, dict2, dict3)
    expected = {
        'a': [1, None, 5],
        'b': [2, 3, None],
        'c': [None, 4, None],
        'd': [None, None, 6]
    }
    assert result == expected

def test_zip_dicts_empty_dicts():
    """Test with empty dictionaries."""
    result = zip_dicts({}, {}, {})
    assert result == {}

def test_zip_dicts_single_dict():
    """Test with a single dictionary."""
    dict1 = {'a': 1, 'b': 2}
    result = zip_dicts(dict1)
    expected = {'a': [1], 'b': [2]}
    assert result == expected

def test_zip_dicts_no_dicts():
    """Test with no dictionaries provided."""
    result = zip_dicts()
    assert result == {}

def test_zip_dicts_partial_overlap():
    """Test with dictionaries that have partial key overlap."""
    dict1 = {'a': 1, 'b': 2}
    dict2 = {'b': 3, 'c': 4}
    dict3 = {'c': 5, 'd': 6}

    result = zip_dicts(dict1, dict2, dict3)
    expected = {
        'a': [1, None, None],
        'b': [2, 3, None],
        'c': [None, 4, 5],
        'd': [None, None, 6]
    }
    assert result == expected

def test_zip_dicts_identical_keys():
    """Test with dictionaries that have identical keys."""
    dict1 = {'a': 1, 'b': 2}
    dict2 = {'a': 3, 'b': 4}
    dict3 = {'a': 5, 'b': 6}

    result = zip_dicts(dict1, dict2, dict3)
    expected = {
        'a': [1, 3, 5],
        'b': [2, 4, 6]
    }
    assert result == expected

def test_zip_dicts_mixed_types():
    """Test with dictionaries containing mixed value types."""
    dict1 = {'a': 1, 'b': 'hello'}
    dict2 = {'a': 3.14, 'c': [1, 2, 3]}
    dict3 = {'a': None, 'd': {'key': 'value'}}

    result = zip_dicts(dict1, dict2, dict3)
    expected = {
        'a': [1, 3.14, None],
        'b': ['hello', None, None],
        'c': [None, [1, 2, 3], None],
        'd': [None, None, {'key': 'value'}]
    }
    assert result == expected

def test_zip_dicts_non_dict_input():
    """Test that non-dict inputs raise appropriate errors."""
    with pytest.raises(AttributeError):
        zip_dicts({'a': 1}, "not a dict", {'b': 2})

    with pytest.raises(TypeError):
        zip_dicts({'a': 1}, None, {'b': 2})

def test_zip_dicts_custom_objects():
    """Test with custom objects as values."""
    class CustomObj:
        def __init__(self, value):
            self.value = value

    obj1 = CustomObj(1)
    obj2 = CustomObj(2)

    dict1 = {'a': obj1}
    dict2 = {'a': obj2, 'b': obj1}

    result = zip_dicts(dict1, dict2)
    expected = {
        'a': [obj1, obj2],
        'b': [None, obj1]
    }
    assert result == expected
    assert result['a'][0] is obj1
    assert result['a'][1] is obj2
    assert result['b'][1] is obj1
```

